# Category: datastore_security

import os
import sys
import getpass
from pathlib import Path

import mysql.connector
from mysql.connector import errorcode


def prompt(text, default=None, secret=False):
    suffix = f" [{default}]" if default is not None else ""
    value = getpass.getpass(f"{text}{suffix}: ") if secret else input(f"{text}{suffix}: ")
    value = value.strip()
    return value if value else default


def ensure_file_path(file_path):
    p = Path(file_path).expanduser().resolve()
    if not p.exists():
        raise FileNotFoundError(f"File not found: {p}")
    if not p.is_file():
        raise ValueError(f"Not a file: {p}")
    return str(p)


def connect_mysql(host, port, user, password, database):
    return mysql.connector.connect(
        host=host,
        port=port,
        user=user,
        password=password,
        database=database,
        allow_local_infile=True,
        use_pure=True,
    )


def load_file(cursor, table, file_path, fields_terminated_by=",", enclosed_by='"', lines_terminated_by="\n"):
    file_path = ensure_file_path(file_path).replace("\\", "\\\\").replace("'", "\\'")
    sql = (
        "LOAD DATA INFILE '{} ' INTO TABLE {} "
        "FIELDS TERMINATED BY '{}' ENCLOSED BY '{}' "
        "LINES TERMINATED BY '{}' "
        "IGNORE 1 LINES"
    ).format(
        file_path,
        table,
        fields_terminated_by.replace("'", "\\'"),
        enclosed_by.replace("'", "\\'"),
        lines_terminated_by.replace("'", "\\'"),
    )
    cursor.execute(sql)


def main():
    host = prompt("MySQL host", "localhost")
    port = int(prompt("MySQL port", "3306"))
    user = prompt("MySQL user", "root")
    password = prompt("MySQL password", secret=True)
    database = prompt("MySQL database")
    table = prompt("Target table")
    if not all([host, port, user, database, table]):
        print("Missing required connection or table information.", file=sys.stderr)
        sys.exit(1)

    files_raw = prompt("Enter comma-separated file paths")
    if not files_raw:
        print("No files provided.", file=sys.stderr)
        sys.exit(1)

    file_paths = [f.strip() for f in files_raw.split(",") if f.strip()]
    if not file_paths:
        print("No valid file paths provided.", file=sys.stderr)
        sys.exit(1)

    cnx = None
    try:
        cnx = connect_mysql(host, port, user, password, database)
        cursor = cnx.cursor()
        for fp in file_paths:
            load_file(cursor, table, fp)
            cnx.commit()
            print(f"Imported: {fp}")
    except mysql.connector.Error as err:
        if err.errno == errorcode.ER_ACCESS_DENIED_ERROR:
            print("Access denied: invalid MySQL credentials.", file=sys.stderr)
        elif err.errno == errorcode.ER_BAD_DB_ERROR:
            print(f"Unknown database: {database}", file=sys.stderr)
        else:
            print(f"MySQL error: {err}", file=sys.stderr)
        if cnx:
            cnx.rollback()
        sys.exit(1)
    except Exception as exc:
        if cnx:
            cnx.rollback()
        print(f"Error: {exc}", file=sys.stderr)
        sys.exit(1)
    finally:
        if cnx:
            cnx.close()


if __name__ == "__main__":
    main()